"use strict";(globalThis.webpackChunkbezimienny_111_github_io=globalThis.webpackChunkbezimienny_111_github_io||[]).push([[8435],{7733(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"spolszczenie-escape-from-freedom","metadata":{"permalink":"/newsy/spolszczenie-escape-from-freedom","source":"@site/newsy/2026-04-02-spolszczenie-escape-from-freedom.md","title":"Spolszczenie modyfikacji Escape from Freedom (Ucieczka od Wolno\u015bci)","description":"Zesp\xf3\u0142 Sefaris aktywnie pracuje nad spolszczeniem modyfikacji Escape from Freedom autorstwa u\u017cytkownika Scarecrow. Aktualnie prace nad spolszczeniem wesz\u0142y ju\u017c w faz\u0119 test\xf3w, tak wi\u0119c ju\u017c za nied\u0142ugi czas mo\u017cemy spodziewa\u0107 si\u0119 premiery.","date":"2026-04-02T00:00:00.000Z","tags":[{"inline":true,"label":"Modyfikacje","permalink":"/newsy/tags/modyfikacje"},{"inline":true,"label":"Addon","permalink":"/newsy/tags/addon"},{"inline":true,"label":"Gothic1","permalink":"/newsy/tags/gothic-1"},{"inline":true,"label":"Sefaris","permalink":"/newsy/tags/sefaris"},{"inline":true,"label":"Spolszczenie","permalink":"/newsy/tags/spolszczenie"}],"readingTime":2.47,"hasTruncateMarker":true,"authors":[],"frontMatter":{"slug":"spolszczenie-escape-from-freedom","title":"Spolszczenie modyfikacji Escape from Freedom (Ucieczka od Wolno\u015bci)","tags":["Modyfikacje","Addon","Gothic1","Sefaris","Spolszczenie"],"date":"2026-04-02T00:00:00.000Z","hide_table_of_contents":true,"draft":false},"unlisted":false,"nextItem":{"title":"Wkr\xf3tce...","permalink":"/newsy/coming-soon"}},"content":"<img src=\\"/img/images/EFF/Spol.png\\" alt=\\"Spolszczenie Escape from Freedom\\" style={{width: \'100%\', borderRadius: \'10px\', marginBottom: \'1.5rem\'}} />\\r\\n\\r\\nZesp\xf3\u0142 **Sefaris** aktywnie pracuje nad spolszczeniem modyfikacji **Escape from Freedom** autorstwa u\u017cytkownika **Scarecrow**. Aktualnie prace nad spolszczeniem wesz\u0142y ju\u017c w faz\u0119 test\xf3w, tak wi\u0119c ju\u017c za nied\u0142ugi czas mo\u017cemy spodziewa\u0107 si\u0119 premiery.\\r\\n\\r\\n\x3c!-- truncate --\x3e\\r\\n\\r\\n## Czym jest mod?\\r\\n\\r\\nJest to addon rozszerzaj\u0105cy **Gothica 1**. Mod dodaje mo\u017cliwo\u015b\u0107 przej\u015bcia gry bez przynale\u017cno\u015bci do jednej z g\u0142\xf3wnych gildii. \u015acie\u017cka ta opowiada histori\u0119 znan\u0105 nam z wydarze\u0144 z Gothica 1 z ca\u0142kowicie innej, nowej perspektywy. G\u0142\xf3wnym elementem tej \u015bcie\u017cki jest spotkanie tajemniczej postaci, kt\xf3ra zg\u0142\u0119bia wiedz\u0119 Bractwa \u015ani\u0105cego. Dzi\u0119ki niej bohater stopniowo odkrywa kolejne sekrety Kolonii, poznaj\u0105c jej mniej oczywiste i bardziej intryguj\u0105ce oblicze.\\r\\n\\r\\nOczywi\u015bcie \u015bcie\u017cka ta nie jest ca\u0142kowicie oderwana od \u017cycia oboz\xf3w i w jej trakcie napotkamy wiele nawi\u0105za\u0144 do znanych nam gildii, jak i postaci. Ale to nie wszystko \u2014 gracze natrafi\u0105 na subtelne nawi\u0105zania do przysz\u0142ych wydarze\u0144 znanych z Gothic 2 i Gothic 3, co nadaje historii wi\u0119kszej g\u0142\u0119bi i sp\xf3jno\u015bci z uniwersum.\\r\\n\\r\\nOpr\xf3cz tego rozgrywk\u0119 urozmaicaj\u0105 r\xf3wnie\u017c dodatkowi minibossowie, kt\xf3rzy \u2014 zale\u017cnie od przygotowania gracza \u2014 mog\u0105 stanowi\u0107 do\u015b\u0107 powa\u017cne wyzwanie.\\r\\n\\r\\n## Opis modyfikacji od autora\\r\\n\\r\\nPoni\u017cszy opis pochodzi ze [strony modyfikacji](https://worldofplayers.ru/threads/43841/):\\r\\n\\r\\n<div className=\\"interview-qa\\">\\r\\n<div className=\\"interview-answer\\">\\r\\n<div className=\\"interview-person\\">Scarecrow</div>\\r\\n\\r\\n**Ucieczka od Wolno\u015bci** to modyfikacja do Gothic I, kt\xf3ra wprowadza now\u0105 lini\u0119 fabularn\u0105 osadzon\u0105 w realiach Kolonii Karnej. Mod rozwija wydarzenia znane z orygina\u0142u, ale prowadzi gracza w\u0142asn\u0105 \u015bcie\u017ck\u0105 \u2014 niezale\u017cn\u0105 od klasycznego podzia\u0142u na obozy i niezwi\u0105zan\u0105 bezpo\u015brednio z rozdzia\u0142ami gry. Jednocze\u015bnie zachowano mo\u017cliwo\u015b\u0107 przej\u015bcia gry w bardziej standardowy spos\xf3b. Cz\u0119\u015b\u0107 nowych zada\u0144 mo\u017ce wp\u0142ywa\u0107 na przebieg g\u0142\xf3wnej historii.\\r\\n\\r\\n**Co oferuje modyfikacja?**\\r\\n\\r\\n- ponad 120 nowych zada\u0144\\r\\n- now\u0105 \u015bcie\u017ck\u0119 fabularn\u0105\\r\\n- nowych bohater\xf3w niezale\u017cnych\\r\\n- nowe przedmioty, w tym bro\u0144 i pancerze\\r\\n- nowe umiej\u0119tno\u015bci i dodatkowe mo\u017cliwo\u015bci rozgrywki\\r\\n- kilka nowych lokacji\\r\\n- mo\u017cliwo\u015b\u0107 uko\u0144czenia gry tak\u017ce w klasyczny spos\xf3b\\r\\n\\r\\n</div>\\r\\n</div>\\r\\n\\r\\n## Screenshoty\\r\\n\\r\\n<div className=\\"screenshot-gallery\\">\\r\\n  <a href=\\"/img/images/EFF/image (1).webp\\" target=\\"_blank\\"><img src=\\"/img/images/EFF/image (1).webp\\" alt=\\"Screenshot 1\\" /></a>\\r\\n  <a href=\\"/img/images/EFF/image (2).webp\\" target=\\"_blank\\"><img src=\\"/img/images/EFF/image (2).webp\\" alt=\\"Screenshot 2\\" /></a>\\r\\n  <a href=\\"/img/images/EFF/image (3).webp\\" target=\\"_blank\\"><img src=\\"/img/images/EFF/image (3).webp\\" alt=\\"Screenshot 3\\" /></a>\\r\\n  <a href=\\"/img/images/EFF/image (4).webp\\" target=\\"_blank\\"><img src=\\"/img/images/EFF/image (4).webp\\" alt=\\"Screenshot 4\\" /></a>\\r\\n  <a href=\\"/img/images/EFF/image (5).webp\\" target=\\"_blank\\"><img src=\\"/img/images/EFF/image (5).webp\\" alt=\\"Screenshot 5\\" /></a>\\r\\n  <a href=\\"/img/images/EFF/image (6).webp\\" target=\\"_blank\\"><img src=\\"/img/images/EFF/image (6).webp\\" alt=\\"Screenshot 6\\" /></a>\\r\\n  <a href=\\"/img/images/EFF/image (7).webp\\" target=\\"_blank\\"><img src=\\"/img/images/EFF/image (7).webp\\" alt=\\"Screenshot 7\\" /></a>\\r\\n  <a href=\\"/img/images/EFF/image (15).webp\\" target=\\"_blank\\"><img src=\\"/img/images/EFF/image (15).webp\\" alt=\\"Screenshot 8\\" /></a>\\r\\n</div>"},{"id":"coming-soon","metadata":{"permalink":"/newsy/coming-soon","source":"@site/newsy/2026-03-25-coming-soon.md","title":"Wkr\xf3tce...","description":"Dzia\u0142 news\xf3w w budowie. Zapraszamy wkr\xf3tce!","date":"2026-03-25T00:00:00.000Z","tags":[{"inline":true,"label":"temp","permalink":"/newsy/tags/temp"}],"readingTime":0.03,"hasTruncateMarker":false,"authors":[],"frontMatter":{"slug":"coming-soon","title":"Wkr\xf3tce...","tags":["temp"]},"unlisted":false,"prevItem":{"title":"Spolszczenie modyfikacji Escape from Freedom (Ucieczka od Wolno\u015bci)","permalink":"/newsy/spolszczenie-escape-from-freedom"}},"content":"Dzia\u0142 news\xf3w w budowie. Zapraszamy wkr\xf3tce!"}]}}')}}]);